class Solution(object):
    def smallestString(self, s):
        # Decreasing a char makes it smaller, except 'a' -> 'z' makes it larger.
        # Greedy: find leftmost non-'a' char, decrement all consecutive non-'a' chars.
        # If entire string is 'a', we must change one char (last 'a' -> 'z').
        res = list(s)
        n = len(s)
        i = 0
        # Skip leading 'a's
        while i < n and res[i] == 'a':
            i += 1
        if i == n:
            # All 'a's, must change last to 'z'
            res[-1] = 'z'
            return ''.join(res)
        # Decrement all consecutive non-'a' chars starting at i
        while i < n and res[i] != 'a':
            res[i] = chr(ord(res[i]) - 1)
            i += 1
        return ''.join(res)
